class Solution {
    public Node flatten(Node head) {
        flattenHelper(head);
        return head;
    }

    private Node flattenHelper(Node node) {
        Node current = node;
        Node lastNode = node;

        while (current != null) {
            Node next = current.next;
            if (current.child != null) {
                Node childTail = flattenHelper(current.child);
                current.next = current.child;
                current.child.prev = current;
                current.child = null;

                childTail.next = next;
                if (next != null) next.prev = childTail;
                lastNode = childTail;
            } else {
                lastNode = current;
            }
            current = next;
        }
        return lastNode;
    }
}

